import json
d=json.load(open('data.json'))
ex=d['arc-gen']
def dims(g): return len(g),len(g[0])
# H_A: shift right by 1 for non-bottom rows, keep bottom rows (NO clamp)
def pA(g):
    W=len(g[0]);G=[r+[0] for r in g]+[[0]*W]
    o=[]
    for a,b in zip(G,G[1:]):
        if any(b): o.append([0]+a[:W-1])
        else: o.append(a[:W])
    return o
def count(p):
    return sum(p(e['input'])!=e['output'] for e in ex)
print('H_A shift-noclamp fails:',count(pA))
# how many cells differ total for H_A (to gauge clamp impact)
tot=0
for e in ex:
    got=pA(e['input']);exp=e['output']
    for gr,er in zip(got,exp):
        for gc,ec in zip(gr,er):
            if gc!=ec: tot+=1
print('H_A total differing cells:',tot,'over',len(ex),'examples')
